INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('real-estate-appraiser-moex-00333', 'real-estate-appraiser', 'real-estate-appraiser-moex-101-9a386a01', 'sub-real-estate-appraiser-08', NULL, 'single_choice', '「徐渭，字文長，為山陰諸生，聲名籍甚。薛公蕙校越時，奇其才，有國士之目。然數奇，屢試輒蹶。 中丞胡公宗憲聞之，客諸幕。」（袁宏道〈徐文長傳〉） 「然數奇，屢試輒蹶」一句中，「奇」的意涵與下列那一選項相同？', '["命運不好", "超乎尋常", "令人驚異", "怪異難解"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:05+00:00", "source_pdf_sha1": "2d40ecc2b83f", "answer_pdf_sha1": "e5c67479d01d", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "905", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "appraiser", "db_exam_id": "real-estate-appraiser"}'::jsonb, NULL),
  ('real-estate-appraiser-moex-00334', 'real-estate-appraiser', 'real-estate-appraiser-moex-101-9a386a01', 'sub-real-estate-appraiser-08', NULL, 'single_choice', '古者諫無官，自公卿大夫，至於工商，無不得諫者。漢興以來，始置官。夫以天下之政，四海之眾， 得失利病，萃於一官。使言之，其為任亦重矣。居是官者，當志其大，舍其細，先其急，後其緩，專利 國家，而不為身謀。（司馬光〈諫院題名記〉） 下列敘述何者最貼近上文所強調的諫官之德？', '["知所不為，行己有恥", "權衡輕重，先公後私", "察納雅言，隱惡揚善", "見利思義，見危授命"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:05+00:00", "source_pdf_sha1": "2d40ecc2b83f", "answer_pdf_sha1": "e5c67479d01d", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "905", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "appraiser", "db_exam_id": "real-estate-appraiser"}'::jsonb, NULL),
  ('real-estate-appraiser-moex-00335', 'real-estate-appraiser', 'real-estate-appraiser-moex-101-9a386a01', 'sub-real-estate-appraiser-08', NULL, 'single_choice', '衛人嫁其子而教之曰：「必私積聚。為人婦而出，常也；其成居，幸也。」其子因私積聚，其姑以為多 私而出之。其子所以反者，倍其所以嫁。其父不自罪於教子非也，而自知其益富。今人臣之處官者，皆 是類也。（《韓非子．說林上》） 以下選項何者最接近「今人臣之處官者」的啟示？', '["為官者愛財，也應取之有道", "為官者若無遠慮，必有近憂", "為官者勿營私好利，以免招禍", "為官首重廉，不廉則無所不取"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:05+00:00", "source_pdf_sha1": "2d40ecc2b83f", "answer_pdf_sha1": "e5c67479d01d", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "905", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "appraiser", "db_exam_id": "real-estate-appraiser"}'::jsonb, NULL),
  ('real-estate-appraiser-moex-00336', 'real-estate-appraiser', 'real-estate-appraiser-moex-101-9a386a01', 'sub-real-estate-appraiser-08', NULL, 'single_choice', '齊侯問于晏子曰：「為政何患？」對曰：「患善惡之不分。」公曰：「何以察之？」對曰：「審擇左右， 左右善，則百僚各得其所宜而善惡分。」孔子聞之曰：「此言也信矣，善言進，則不善無由入矣；不進 善言，則善無由入矣。」（《說苑．政理》） 下列敘述何者最貼近上文？', '["為政必須明辨是非善惡", "為政必須考慮左右先後的步驟", "百官各司其職則政通人和", "百官多進善言，則各得所宜"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:05+00:00", "source_pdf_sha1": "2d40ecc2b83f", "answer_pdf_sha1": "e5c67479d01d", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "905", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "appraiser", "db_exam_id": "real-estate-appraiser"}'::jsonb, NULL),
  ('real-estate-appraiser-moex-00337', 'real-estate-appraiser', 'real-estate-appraiser-moex-101-9a386a01', 'sub-real-estate-appraiser-08', NULL, 'single_choice', '余光中《青銅一夢．山東甘旅》：「清明節前一星期，我的飛機降落在濟南的遙墻機場。邀請我去齊魯訪 問的雖然是山東大學，真正遠去郊外歡迎的，沒有料到，卻是整個春天。從機場進城，三十公里的高速', '["但兩側的柳樹綠蔭不斷，料峭的晴冷天氣", "千樹新綠排成整齊的春之儀隊", "牽著連綿的青帳翠屏", "那樣盛況的陣仗 下列選項的順序安排，最適合的是："]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:05+00:00", "source_pdf_sha1": "2d40ecc2b83f", "answer_pdf_sha1": "e5c67479d01d", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "905", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "appraiser", "db_exam_id": "real-estate-appraiser"}'::jsonb, NULL),
  ('real-estate-appraiser-moex-00338', 'real-estate-appraiser', 'real-estate-appraiser-moex-101-9a386a01', 'sub-real-estate-appraiser-08', NULL, 'single_choice', '下列文句「」中的成語，何者敘述不當？', '["曾經紅極一時的流行歌曲，在新人新曲競出之後，還是不免成了「明日黃花」", "暢銷書作家常到處演講，成天奔波趕場的狀況幾乎可用「席不暇暖」來形容", "為了達到目的而製造各種謠言來攻擊他人，就有如「蜀犬吠日」，終於有被揭發的一天", "為了不受外界干擾，他「息交絕遊」了一年，斷絕所有的應酬跟娛樂，終於通過了公務人員考試"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:05+00:00", "source_pdf_sha1": "2d40ecc2b83f", "answer_pdf_sha1": "e5c67479d01d", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "905", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "appraiser", "db_exam_id": "real-estate-appraiser"}'::jsonb, NULL),
  ('real-estate-appraiser-moex-00339', 'real-estate-appraiser', 'real-estate-appraiser-moex-101-9a386a01', 'sub-real-estate-appraiser-08', NULL, 'single_choice', '藉由形象化的語言來描繪抽象的情思，可使讀者獲得更鮮明的印象及感受。下列四個選項都運用這種技 巧，何者敘述最為正確？', '["孤獨是一匹衰老的獸／潛伏在我亂石磊磊的心裡──以衰老的獸描寫孤獨離我遠去（楊牧〈孤獨〉）", "問君能有幾多愁？恰似一江春水向東流──以江水東流的方向指出憂愁來源在東方（李煜〈虞美人〉）", "一隻苦瓜，不再是澀苦／日磨月磋琢出深孕的清瑩──苦瓜的外表清瑩，所以不苦（余光中〈白玉苦 瓜〉）", "忽然想起／感傷是微微的了／如遠去的船／船邊的水紋……──傷感似水紋般越來越淡、越小（敻虹〈 水紋〉）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:05+00:00", "source_pdf_sha1": "2d40ecc2b83f", "answer_pdf_sha1": "e5c67479d01d", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "905", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "appraiser", "db_exam_id": "real-estate-appraiser"}'::jsonb, NULL),
  ('real-estate-appraiser-moex-00340', 'real-estate-appraiser', 'real-estate-appraiser-moex-101-9a386a01', 'sub-real-estate-appraiser-08', NULL, 'single_choice', '如果你想引用古代的名言佳句，期勉自己要有「鍥而不捨，不辭艱難」的精神，下列何者最為適合？', '["如切如磋，如琢如磨（《詩經．衛風．淇奧》）", "揀盡寒枝不肯棲，寂寞沙洲冷（蘇軾〈卜算子〉）", "路漫漫其修遠兮，吾將上下而求索（屈原〈離騷〉）", "戰戰兢兢，如臨深淵，如履薄冰（《詩經．小雅．小旻》）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:05+00:00", "source_pdf_sha1": "2d40ecc2b83f", "answer_pdf_sha1": "e5c67479d01d", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "905", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "appraiser", "db_exam_id": "real-estate-appraiser"}'::jsonb, NULL),
  ('real-estate-appraiser-moex-00341', 'real-estate-appraiser', 'real-estate-appraiser-moex-101-9a386a01', 'sub-real-estate-appraiser-08', NULL, 'single_choice', '下列關於先秦諸子的敘述，正確的選項是：', '["墨子：提倡節約，反對奢侈，反對音樂，反對宿命論，認為天沒有意志，是自然天", "莊子：道家代表人物，認為自然、無為、逍遙是道的基本要求，是人生的基本方向", "荀子：儒家代表人物，思想核心為仁、義，將孔子的德治發展成為仁政，提倡禮法兼治", "韓非子：法家代表人物，於政治上主張只要國君遵行法理，不須依賴術、勢，便能安定國家"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:05+00:00", "source_pdf_sha1": "2d40ecc2b83f", "answer_pdf_sha1": "e5c67479d01d", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "905", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "appraiser", "db_exam_id": "real-estate-appraiser"}'::jsonb, NULL),
  ('real-estate-appraiser-moex-00342', 'real-estate-appraiser', 'real-estate-appraiser-moex-101-9a386a01', 'sub-real-estate-appraiser-08', NULL, 'single_choice', '「對酒當歌，人生幾何？譬如朝露，去日苦多。慨當以慷，憂思難忘；何以解憂，唯有杜康。青青子衿， 悠悠我心；但為君故，沉吟至今。呦呦鹿鳴，食野之苹。我有嘉賓，鼓瑟吹笙。明明如月，何時可掇？ 憂從中來，不可斷絕。越陌度阡，枉用相存，契闊談讌，心念舊恩。月明星稀，烏鵲南飛，繞樹三匝， 何枝可依？山不厭高，海不厭深，周公吐哺，天下歸心。」（曹操〈短歌行〉） 此詩藉助生動的比喻，把抽象的概念化為具體可感的形象，淋漓抒發求賢不得的苦悶和思賢若渴的情意。 以下那個選項敘述錯誤？', '["以「朝露」的轉瞬即逝，比喻人生短促，凸顯求賢的緊迫感", "以「一沐三握髮，一飯三吐哺」的周公自比，表示對天下賢士的熱誠歡迎", "用「明明如月，何時可掇？憂從中來，不可斷絕」，抒發賢士有志難伸、懷才不遇的感傷", "透過「我有嘉賓，鼓瑟吹笙」和「契闊談讌，心念舊恩」之宴請賓客，表現禮賢下士、慕悅賢才的心意"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:05+00:00", "source_pdf_sha1": "2d40ecc2b83f", "answer_pdf_sha1": "e5c67479d01d", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "905", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "appraiser", "db_exam_id": "real-estate-appraiser"}'::jsonb, NULL)
